11	
12	  /** Constructs a port for the current Module.
13	    *
14	    * This must wrap the datatype used to set the io field of any Module.
15	    * i.e. All concrete modules must have defined io in this form:
16	    * [lazy] val io[: io type] = IO(...[: io type])
17	    *
18	    * Items in [] are optional.
19	    *
20	    * The granted iodef must be a chisel type and not be bound to hardware.
21	    *
22	    * Also registers a Data as a port, also performing bindings. Cannot be called once ports are
23	    * requested (so that all calls to ports will return the same information).
24	    */
25	  def apply[T <: Data](iodef: => T)(implicit sourceInfo: SourceInfo): T = {
26	    val module = Module.currentModule.get // Impossible to fail
27	    if (!module.isIOCreationAllowed)
